export const getSearchKnightedJobsUrl = (params?: SearchKnightedJobsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/knighted-jobs/search?${stringifiedParams}` : `/api/knighted-jobs/search`
}

